arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_eaff7f2a19ab410a9fac65174b7d4487.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        <div class="position-absolute" style="top:18px;left:10%;right:10%;height:2px;background:#dee2e6;z-index:0;"></div>
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i + 1;
            var isCompleted = step < _currentStep;
            var isCurrent = step == _currentStep;
            var isFuture = step > _currentStep;
            <div class="text-center position-relative" style="z-index:1;flex:1;">
                <button class="btn rounded-circle d-inline-flex align-items-center justify-content-center p-0 @StepBadgeClass(step)"
                        style="width:36px;height:36px;font-size:0.85rem;"
                        disabled="@(isFuture || _submitted)"
                        @onclick="() => GoToStep(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </button>
                <div class="small mt-1 @(isFuture ? "text-muted" : "")">@StepLabels[i]</div>
            </div>
        }
    </nav>

    @if (_submitted)
    {
        @* ───── Confirmation ───── *@
        <div class="alert alert-success text-center py-5">
            <h3>&#10003; Application Submitted!</h3>
            <p class="lead mb-0">Your application ID is <strong>@_applicationId</strong>.</p>
            <p class="text-muted mt-2">We will contact you at @_email.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_errorMessage))
        {
            <div class="alert alert-danger">@_errorMessage</div>
        }

        @switch (_currentStep)
        {
            case 1:
                @RenderStep1()
                break;
            case 2:
                @RenderStep2()
                break;
            case 3:
                @RenderStep3()
                break;
            case 4:
                @RenderStep4()
                break;
            case 5:
                @RenderStep5()
                break;
        }
    }
</div>

@* ───── Step 1: Personal Info ───── *@
@{
    RenderFragment RenderStep1() => __builder =>
    {
        <h4 class="mb-3">Personal Information</h4>
        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="_fullName" @bind:event="oninput" placeholder="Jane Doe" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="_email" @bind:event="oninput" placeholder="jane@example.com" />
            @if (_emailValidating)
            {
                <div class="form-text text-info">Validating email…</div>
            }
        </div>
        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
        </div>
        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="NextFromStep1" disabled="@_emailValidating">Next &rarr;</button>
        </div>
    };
