@code {
    // ── Step state ──
    private static readonly string[] StepLabels = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
    private int _currentStep = 1;
    private string _errorMessage = string.Empty;

    // ── Step 1 fields ──
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;
    private bool _emailValidating;

    // ── Step 2 fields ──
    private List<WorkEntryModel> _workEntries = [new()];

    // ── Step 3 fields ──
    private List<ReferenceEntry> _references = [new(), new()];

    // ── Step 4 fields ──
    private string _coverLetter = string.Empty;

    // ── Submission ──
    private bool _submitting;
    private bool _submitted;
    private int _applicationId;

    // ── Mutable helper classes ──
    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private class ReferenceEntry
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }

    // ── Step navigation helpers ──
    private string StepBadgeClass(int step)
    {
        if (step < _currentStep) return "btn-success text-white";
        if (step == _currentStep) return "btn-primary text-white";
        return "btn-outline-secondary";
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    // ── Step 1 validation ──
    private async Task NextFromStep1()
    {
        _errorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _emailValidating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            _emailValidating = false;
        }

        _currentStep = 2;
    }

    // ── Step 2 helpers ──
    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
    }

    private void NextFromStep2()
    {
        _errorMessage = string.Empty;

        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate is null)
            {
                _errorMessage = "Each position must have a company, title, and start date.";
                return;
            }
        }

        _currentStep = 3;
    }

    // ── Step 3 validation ──
    private void NextFromStep3()
    {
        _errorMessage = string.Empty;

        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please complete all fields for each reference.";
                return;
            }
        }

        _currentStep = 4;
    }

    // ── Step 4 validation ──
    private void NextFromStep4()
    {
        _errorMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _errorMessage = "Please enter a cover letter.";
            return;
        }

        _currentStep = 5;
    }

    // ── Submit ──
    private async Task SubmitApplication()
    {
        _submitting = true;
        _errorMessage = string.Empty;

        try
        {
            var personal = new PersonalInfo(_fullName.Trim(), _email.Trim(), _phone.Trim(), _address.Trim());

            var work = new WorkHistory(_workEntries.Select(w =>
                new WorkEntry(w.Company.Trim(), w.Title.Trim(), w.StartDate!.Value, w.IsCurrent ? null : w.EndDate, w.Description.Trim())
            ).ToList());

            var refs = _references.Select(r =>
                new Reference(r.Name.Trim(), r.Relationship.Trim(), r.Email.Trim(), r.Phone.Trim())
            ).ToList();

            var application = new JobApplication(personal, work, refs, _coverLetter.Trim());
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

