+            <button class="btn btn-secondary" @onclick="() => _currentStep = 1">&larr; Back</button>
+            <button class="btn btn-primary" @onclick="NextFromStep2">Next &rarr;</button>
+        </div>
+    };
+}
+
+@* ───── Step 3: References ───── *@
+@{
+    RenderFragment RenderStep3() => __builder =>
+    {
+        <h4 class="mb-3">References</h4>
+        @for (int idx = 0; idx < _references.Count; idx++)
+        {
+            var i = idx;
+            var r = _references[i];
+            <div class="card mb-3">
+                <div class="card-body">
+                    <div class="d-flex justify-content-between align-items-center mb-2">
+                        <h6 class="mb-0">Reference @(i + 1)</h6>
+                        @if (_references.Count > 2)
+                        {
+                            <button class="btn btn-outline-danger btn-sm" @onclick="() => _references.RemoveAt(i)">Remove</button>
+                        }
+                    </div>
+                    <div class="row g-2 mb-2">
+                        <div class="col-md-6">
+                            <label class="form-label">Name <span class="text-danger">*</span></label>
+                            <input class="form-control" value="@r.Name" @oninput="e => r.Name = e.Value?.ToString() ?? string.Empty" />
+                        </div>
+                        <div class="col-md-6">
+                            <label class="form-label">Relationship <span class="text-danger">*</span></label>
+                            <input class="form-control" value="@r.Relationship" @oninput="e => r.Relationship = e.Value?.ToString() ?? string.Empty" placeholder="e.g. Former Manager" />
+                        </div>
+                    </div>
+                    <div class="row g-2">
+                        <div class="col-md-6">
+                            <label class="form-label">Email <span class="text-danger">*</span></label>
+                            <input type="email" class="form-control" value="@r.Email" @oninput="e => r.Email = e.Value?.ToString() ?? string.Empty" />
+                        </div>
+                        <div class="col-md-6">
+                            <label class="form-label">Phone <span class="text-danger">*</span></label>
+                            <input type="tel" class="form-control" value="@r.Phone" @oninput="e => r.Phone = e.Value?.ToString() ?? string.Empty" />
+                        </div>
+                    </div>
+                </div>
+            </div>
+        }
+        @if (_references.Count < 3)
+        {
+            <button class="btn btn-outline-secondary mb-3" @onclick="() => _references.Add(new ReferenceEntry())">+ Add Reference</button>
+        }
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="() => _currentStep = 2">&larr; Back</button>
+            <button class="btn btn-primary" @onclick="NextFromStep3">Next &rarr;</button>
+        </div>
+    };
+}
+
+@* ───── Step 4: Cover Letter ───── *@
+@{
+    RenderFragment RenderStep4() => __builder =>
+    {
+        <h4 class="mb-3">Cover Letter</h4>
+        <div class="mb-2">
+            <textarea class="form-control" rows="10" @bind="_coverLetter" @bind:event="oninput"
+                      placeholder="Tell us why you're a great fit for this role…" maxlength="2000"></textarea>
+        </div>
+        <div class="form-text text-end mb-3">@_coverLetter.Length / 2000 characters</div>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="() => _currentStep = 3">&larr; Back</button>
+            <button class="btn btn-primary" @onclick="NextFromStep4">Next &rarr;</button>
+        </div>
+    };
+}
+
+@* ───── Step 5: Review & Submit ───── *@
+@{
+    RenderFragment RenderStep5() => __builder =>
+    {
+        <h4 class="mb-3">Review &amp; Submit</h4>
+
+        @* Personal Info *@
+        <div class="card mb-3">
+            <div class="card-header d-flex justify-content-between align-items-center">
+                <strong>Personal Information</strong>
+                <button class="btn btn-link btn-sm p-0" @onclick='() => _currentStep = 1'>Edit</button>
+            </div>
+            <div class="card-body">
+                <dl class="row mb-0">
+                    <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@_fullName</dd>
+                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
+                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
+                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
+                </dl>
+            </div>
+        </div>
+
+        @* Work History *@
+        <div class="card mb-3">
+            <div class="card-header d-flex justify-content-between align-items-center">
+                <strong>Work History</strong>
+                <button class="btn btn-link btn-sm p-0" @onclick='() => _currentStep = 2'>Edit</button>
+            </div>
+            <div class="card-body">
+                @foreach (var w in _workEntries)
+                {
+                    <div class="mb-2">
+                        <strong>@w.Title</strong> at @w.Company<br />
+                        <small class="text-muted">
+                            @w.StartDate?.ToString("MMM yyyy") &ndash; @(w.IsCurrent ? "Present" : w.EndDate?.ToString("MMM yyyy"))
+                        </small>
+                        @if (!string.IsNullOrWhiteSpace(w.Description))
+                        {
+                            <p class="mb-0 mt-1">@w.Description</p>
+                        }
+                    </div>
+                }
+            </div>
+        </div>
+
+        @* References *@
+        <div class="card mb-3">
+            <div class="card-header d-flex justify-content-between align-items-center">
+                <strong>References</strong>
+                <button class="btn btn-link btn-sm p-0" @onclick='() => _currentStep = 3'>Edit</button>
+            </div>
+            <div class="card-body">
+                @foreach (var r in _references)
+                {
+                    <div class="mb-2">
+                        <strong>@r.Name</strong> — @r.Relationship<br />
+                        <small class="text-muted">@r.Email &middot; @r.Phone</small>
+                    </div>
+                }
+            </div>
+        </div>
+
+        @* Cover Letter *@
+        <div class="card mb-3">
+            <div class="card-header d-flex justify-content-between align-items-center">
+                <strong>Cover Letter</strong>
+                <button class="btn btn-link btn-sm p-0" @onclick='() => _currentStep = 4'>Edit</button>
+            </div>
+            <div class="card-body">
+                <p style="white-space:pre-wrap;" class="mb-0">@_coverLetter</p>
+            </div>
+        </div>
+
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="() => _currentStep = 4">&larr; Back</button>
+            <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_submitting">
+                @if (_submitting)
+                {
+                    <span class="spinner-border spinner-border-sm me-1"></span>
+                }
+                Submit Application
+            </button>
+        </div>
+    };
+}
+
+@code {
+    // ── Step state ──
+    private static readonly string[] StepLabels = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
+    private int _currentStep = 1;
+    private string _errorMessage = string.Empty;
+
+    // ── Step 1 fields ──
+    private string _fullName = string.Empty;
+    private string _email = string.Empty;
+    private string _phone = string.Empty;
+    private string _address = string.Empty;
+    private bool _emailValidating;
+
+    // ── Step 2 fields ──
+    private List<WorkEntryModel> _workEntries = [new()];
+
+    // ── Step 3 fields ──
+    private List<ReferenceEntry> _references = [new(), new()];
+
+    // ── Step 4 fields ──
+    private string _coverLetter = string.Empty;
+
+    // ── Submission ──
+    private bool _submitting;
+    private bool _submitted;
+    private int _applicationId;
+
+    // ── Mutable helper classes ──
+    private class WorkEntryModel
+    {
+        public string Company { get; set; } = string.Empty;
+        public string Title { get; set; } = string.Empty;
+        public DateTime? StartDate { get; set; }
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string Description { get; set; } = string.Empty;
+    }
+
+    private class ReferenceEntry
+    {
+        public string Name { get; set; } = string.Empty;
+        public string Relationship { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+    }
+
+    // ── Step navigation helpers ──
+    private string StepBadgeClass(int step)
+    {
+        if (step < _currentStep) return "btn-success text-white";
+        if (step == _currentStep) return "btn-primary text-white";
+        return "btn-outline-secondary";
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step < _currentStep && !_submitted)
+        {
+            _errorMessage = string.Empty;
+            _currentStep = step;
+        }
+    }
+
+    // ── Step 1 validation ──
+    private async Task NextFromStep1()
+    {
+        _errorMessage = string.Empty;
+
+        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
+            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
+        {
+            _errorMessage = "Please fill in all required fields.";
+            return;
+        }
+
+        _emailValidating = true;
+        try
+        {
+            var valid = await ApplicationService.ValidateEmailAsync(_email);
+            if (!valid)
+            {
+                _errorMessage = "Please enter a valid email address.";
+                return;
+            }
+        }
+        finally
+        {
+            _emailValidating = false;
+        }
+
+        _currentStep = 2;
+    }
+
+    // ── Step 2 helpers ──
+    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());
+
+    private void RemoveWorkEntry(int index)
+    {
+        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
+    }
+
+    private void NextFromStep2()
+    {
+        _errorMessage = string.Empty;
+
+        foreach (var e in _workEntries)
+        {
+            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate is null)
+            {
+                _errorMessage = "Each position must have a company, title, and start date.";
+                return;
+            }
+        }
+
+        _currentStep = 3;
+    }
+
+    // ── Step 3 validation ──
+    private void NextFromStep3()
+    {
+        _errorMessage = string.Empty;
+
+        foreach (var r in _references)
+        {
+            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
+                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
+            {
+                _errorMessage = "Please complete all fields for each reference.";
+                return;
+            }
+        }
+
+        _currentStep = 4;
+    }
+
+    // ── Step 4 validation ──
+    private void NextFromStep4()
+    {
+        _errorMessage = string.Empty;
+
+        if (string.IsNullOrWhiteSpace(_coverLetter))
+        {
+            _errorMessage = "Please enter a cover letter.";
+            return;
+        }
+
+        _currentStep = 5;
+    }
+
+    // ── Submit ──
+    private async Task SubmitApplication()
+    {
+        _submitting = true;
+        _errorMessage = string.Empty;
+
+        try
+        {
+            var personal = new PersonalInfo(_fullName.Trim(), _email.Trim(), _phone.Trim(), _address.Trim());
+
+            var work = new WorkHistory(_workEntries.Select(w =>
+                new WorkEntry(w.Company.Trim(), w.Title.Trim(), w.StartDate!.Value, w.IsCurrent ? null : w.EndDate, w.Description.Trim())
+            ).ToList());
+
+            var refs = _references.Select(r =>
+                new Reference(r.Name.Trim(), r.Relationship.Trim(), r.Email.Trim(), r.Phone.Trim())
+            ).ToList();
+
+            var application = new JobApplication(personal, work, refs, _coverLetter.Trim());
+            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
+            _submitted = true;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            _submitting = false;
+        }
+    }
+}
+
